import type { PrismaClient } from "@prisma/client";
import { prisma as defaultPrisma } from "./client.js";

/**
 * Per-admin moderation-decision history: one row per action an admin applies
 * (warn, mute, kick, ban, delete, ...), tagged with the rule/context that
 * triggered it (`ruleId`). Feeds two audit detectors in
 * `modules/security/src` that need this history but have no I/O of their
 * own: `aggressive-admin.ts` (detectAggressiveAdmins, needs a per-admin
 * sanction COUNT) and `consistency-check.ts` (detectInconsistency, needs
 * {adminId, caseKind, action} records). Neither is derivable from the
 * existing ModerationCase/Sanction/Warning tables today: those key off the
 * *subject* user, not the acting admin, and the only admin reference
 * (`ModerationCase.payload.actorUserId`) is unindexed JSON and only covers
 * the warn/sanction flow, not every moderation action (e.g. plain kicks).
 */

/** One moderation decision applied by an admin, to be recorded verbatim. */
export interface RecordAdminDecisionInput {
  readonly tenantId: string;
  readonly chatId: string;
  /** Telegram user id of the admin who applied the action. */
  readonly adminId: bigint;
  /** e.g. "warn" | "mute" | "kick" | "ban" | "delete". Free-form, lowercased by callers. */
  readonly action: string;
  /** The rule/case-kind/context that triggered this decision, if known. */
  readonly ruleId?: string;
}

/** A recorded decision, read back for audit reports. */
export interface AdminDecisionEntry {
  readonly adminId: bigint;
  readonly action: string;
  readonly ruleId: string | undefined;
  readonly occurredAt: Date;
}

export interface AdminDecisionRepository {
  /** Appends one decision to the history. Never mutates or dedupes. */
  record(input: RecordAdminDecisionInput): Promise<void>;
  /**
   * Most recent decisions for a chat, newest first, for the two audit
   * detectors (aggressive-admin, consistency-check) to aggregate over.
   */
  listRecent(
    tenantId: string,
    chatId: string,
    limit?: number,
  ): Promise<AdminDecisionEntry[]>;
}

const MAX_PER_CHAT = 1000;

export class PrismaAdminDecisionRepository implements AdminDecisionRepository {
  constructor(private readonly client: PrismaClient = defaultPrisma) {}

  async record(input: RecordAdminDecisionInput): Promise<void> {
    await this.client.adminDecision.create({
      data: {
        tenantId: input.tenantId,
        chatId: input.chatId,
        adminId: input.adminId,
        action: input.action,
        ruleId: input.ruleId ?? null,
      },
    });
  }

  async listRecent(
    tenantId: string,
    chatId: string,
    limit = 200,
  ): Promise<AdminDecisionEntry[]> {
    const rows = await this.client.adminDecision.findMany({
      where: { tenantId, chatId },
      orderBy: { occurredAt: "desc" },
      take: limit,
    });
    return rows.map((row) => ({
      adminId: row.adminId,
      action: row.action,
      ruleId: row.ruleId ?? undefined,
      occurredAt: row.occurredAt,
    }));
  }
}

/** Store en memoria usado como default del constructor (tests). */
export class InMemoryAdminDecisionRepository implements AdminDecisionRepository {
  private readonly decisions = new Map<
    string,
    Array<AdminDecisionEntry>
  >();

  private key(tenantId: string, chatId: string): string {
    return `${tenantId}:${chatId}`;
  }

  async record(input: RecordAdminDecisionInput): Promise<void> {
    const key = this.key(input.tenantId, input.chatId);
    const entry: AdminDecisionEntry = {
      adminId: input.adminId,
      action: input.action,
      ruleId: input.ruleId,
      occurredAt: new Date(),
    };
    const list = this.decisions.get(key) ?? [];
    list.unshift(entry);
    if (list.length > MAX_PER_CHAT) {
      list.length = MAX_PER_CHAT;
    }
    this.decisions.set(key, list);
  }

  async listRecent(
    tenantId: string,
    chatId: string,
    limit = 200,
  ): Promise<AdminDecisionEntry[]> {
    const list = this.decisions.get(this.key(tenantId, chatId)) ?? [];
    return list.slice(0, limit);
  }
}

repositoryTestFileContent:
import { describe, expect, it } from "vitest";
import { InMemoryAdminDecisionRepository } from "./admin-decision-repository.js";

describe("InMemoryAdminDecisionRepository", () => {
  it("records and lists decisions for a chat, newest first", async () => {
    const repo = new InMemoryAdminDecisionRepository();
    await repo.record({
      tenantId: "t1",
      chatId: "c1",
      adminId: 100n,
      action: "warn",
      ruleId: "spam",
    });
    await repo.record({
      tenantId: "t1",
      chatId: "c1",
      adminId: 100n,
      action: "ban",
      ruleId: "spam",
    });

    const entries = await repo.listRecent("t1", "c1");
    expect(entries).toHaveLength(2);
    expect(entries[0]?.action).toBe("ban");
    expect(entries[1]?.action).toBe("warn");
    expect(entries.every((e) => e.adminId === 100n)).toBe(true);
    expect(entries.every((e) => e.ruleId === "spam")).toBe(true);
  });

  it("keeps decisions scoped per (tenant, chat)", async () => {
    const repo = new InMemoryAdminDecisionRepository();
    await repo.record({
      tenantId: "t1",
      chatId: "c1",
      adminId: 1n,
      action: "mute",
    });
    await repo.record({
      tenantId: "t1",
      chatId: "c2",
      adminId: 2n,
      action: "kick",
    });
    await repo.record({
      tenantId: "t2",
      chatId: "c1",
      adminId: 3n,
      action: "ban",
    });

    expect(await repo.listRecent("t1", "c1")).toHaveLength(1);
    expect(await repo.listRecent("t1", "c2")).toHaveLength(1);
    expect(await repo.listRecent("t2", "c1")).toHaveLength(1);
    expect((await repo.listRecent("t1", "c1"))[0]?.adminId).toBe(1n);
  });

  it("leaves ruleId undefined when not provided", async () => {
    const repo = new InMemoryAdminDecisionRepository();
    await repo.record({
      tenantId: "t1",
      chatId: "c1",
      adminId: 1n,
      action: "delete",
    });
    const [entry] = await repo.listRecent("t1", "c1");
    expect(entry?.ruleId).toBeUndefined();
  });

  it("respects the limit parameter", async () => {
    const repo = new InMemoryAdminDecisionRepository();
    for (let i = 0; i < 5; i += 1) {
      await repo.record({
        tenantId: "t1",
        chatId: "c1",
        adminId: 1n,
        action: `action-${i}`,
      });
    }
    const entries = await repo.listRecent("t1", "c1", 2);
    expect(entries).toHaveLength(2);
    expect(entries[0]?.action).toBe("action-4");
    expect(entries[1]?.action).toBe("action-3");
  });
});

prismaModelSnippet:
/// Per-admin moderation-decision history (audit-only): one row per applied
/// action, tagged with the rule/context that triggered it. Feeds the
/// aggressive-admin and consistency-check detectors in modules/security/src.
/// No `@relation` fields (same convention as ChatActivityEvent) so it can be
/// appended without touching the Tenant/Chat models' back-relation arrays.
model AdminDecision {
  id         String   @id @default(cuid())
  tenantId   String
  chatId     String
  adminId    BigInt
  action     String
  ruleId     String?
  occurredAt DateTime @default(now())

  @@index([tenantId, chatId, occurredAt])
  @@index([tenantId, adminId])
  @@map("admin_decisions")
}

